```python
def is_prime(n: int) -> bool:
    """ Check if a number is prime. """
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

def is_palindrome(n: int) -> bool:
    """ Check if a number is a palindrome. """
    return str(n) == str(n)[::-1]

# Generate all palindromic numbers in the range 100-199
palindromic_candidates = list(set(int(''.join(map(str, triple))) for triple in itertools.product(*(range(1, 10)))))

def palindromic_primes(palindromic_candidates, max_digits_required=3):
    """ Function to find all palindromic primes under a maximum number of digits. """
    palindromic_primes_list = []
    for a in palindromic_candidates:
        if len(set(int(str(a)[1]))) == 1:
            if is_prime(a):
                palindromic_primes_list.append(a)
        elif is_prime(a) and len(set(int(str(a)[1]))) == 1:
            palindromic_primes_list.append(a)

    return palindromic_primes_list

